import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"北京天主教堂概览","description":"","frontmatter":{},"headers":[],"relativePath":"religion/catholic-churches.md","filePath":"religion/catholic-churches.md","lastUpdated":1784712887000}'),o={name:"religion/catholic-churches.md"};function n(i,t,s,h,d,g){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="北京天主教堂概览" tabindex="-1">北京天主教堂概览 <a class="header-anchor" href="#北京天主教堂概览" aria-label="Permalink to &quot;北京天主教堂概览&quot;">​</a></h1><blockquote><p>&quot;中西文化交融的见证，哥特式与巴洛克式的建筑瑰宝。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北京是中国天主教传播最早的城市之一。明万历年间，利玛窦等耶稣会士来华传教，在北京建立了中国最早的教堂。历经四百余年的发展，北京留下了众多具有历史价值和艺术价值的天主教堂。</p><h2 id="四大天主教堂" tabindex="-1">四大天主教堂 <a class="header-anchor" href="#四大天主教堂" aria-label="Permalink to &quot;四大天主教堂&quot;">​</a></h2><p>北京最著名的天主教堂被称为&quot;四大堂&quot;，分别是南堂、北堂、东堂、西堂。</p><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">别称</th><th style="text-align:center;">始建年代</th><th style="text-align:center;">建筑风格</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>南堂</strong></td><td style="text-align:left;">宣武门教堂</td><td style="text-align:center;">1605年</td><td style="text-align:center;">巴洛克式</td><td style="text-align:left;">北京最古老的天主教堂</td></tr><tr><td style="text-align:left;"><strong>北堂</strong></td><td style="text-align:left;">西什库教堂</td><td style="text-align:center;">1703年</td><td style="text-align:center;">哥特式</td><td style="text-align:left;">最宏伟华丽</td></tr><tr><td style="text-align:left;"><strong>东堂</strong></td><td style="text-align:left;">王府井教堂</td><td style="text-align:center;">1655年</td><td style="text-align:center;">罗马式</td><td style="text-align:left;">位于繁华商业区</td></tr><tr><td style="text-align:left;"><strong>西堂</strong></td><td style="text-align:left;">西直门教堂</td><td style="text-align:center;">1723年</td><td style="text-align:center;">意大利式</td><td style="text-align:left;">规模最小</td></tr></tbody></table><h2 id="历史背景" tabindex="-1">历史背景 <a class="header-anchor" href="#历史背景" aria-label="Permalink to &quot;历史背景&quot;">​</a></h2><h3 id="利玛窦入京" tabindex="-1">利玛窦入京 <a class="header-anchor" href="#利玛窦入京" aria-label="Permalink to &quot;利玛窦入京&quot;">​</a></h3><p>明万历二十九年（1601年），意大利耶稣会传教士利玛窦抵达北京，成为第一位获准在北京长期居住的西方传教士。利玛窦不仅传播天主教，还将西方科学知识传入中国，同时向欧洲介绍中国文化，被誉为&quot;西学东渐第一人&quot;。</p><p>1605年，利玛窦在北京购得一处住宅，改建成礼拜堂，这就是南堂的雏形。</p><h3 id="康熙与天主教" tabindex="-1">康熙与天主教 <a class="header-anchor" href="#康熙与天主教" aria-label="Permalink to &quot;康熙与天主教&quot;">​</a></h3><p>清代初年，天主教在北京获得较大发展。康熙皇帝对传教士带来的科学知识很感兴趣，任命德国传教士汤若望为钦天监监正，主持编纂历法。</p><p>但在康熙晚年，因&quot;礼仪之争&quot;，清廷禁止天主教传播。直到鸦片战争后，天主教才再次获得传播的机会。</p><h3 id="民国至今" tabindex="-1">民国至今 <a class="header-anchor" href="#民国至今" aria-label="Permalink to &quot;民国至今&quot;">​</a></h3><p>民国时期，天主教在北京有较大发展，新建了许多教堂。新中国成立后，天主教实行独立自主自办教会，北京的天主教堂继续发挥宗教活动场所的作用。</p><h2 id="各堂详细介绍" tabindex="-1">各堂详细介绍 <a class="header-anchor" href="#各堂详细介绍" aria-label="Permalink to &quot;各堂详细介绍&quot;">​</a></h2><h3 id="南堂-宣武门天主堂" tabindex="-1">南堂（宣武门天主堂） <a class="header-anchor" href="#南堂-宣武门天主堂" aria-label="Permalink to &quot;南堂（宣武门天主堂）&quot;">​</a></h3><p>南堂是北京历史最悠久的天主教堂，始建于1605年，由利玛窦创建。现存的建筑是1904年重建的巴洛克式建筑。</p><p><strong>地址</strong>：西城区前门西大街141号<br><strong>交通</strong>：地铁2号线宣武门站B1口<br><strong>弥撒时间</strong>：周日6:30、8:00、10:00、18:00</p><p><a href="/beijing-travel-guide/religion/nantang.html">查看南堂详细介绍 →</a></p><h3 id="北堂-西什库天主堂" tabindex="-1">北堂（西什库天主堂） <a class="header-anchor" href="#北堂-西什库天主堂" aria-label="Permalink to &quot;北堂（西什库天主堂）&quot;">​</a></h3><p>北堂是北京最大、最宏伟的天主教堂，采用典型的哥特式建筑风格。教堂建于1703年，现存建筑是1888年扩建的。</p><p><strong>地址</strong>：西城区西什库大街33号<br><strong>交通</strong>：地铁4号线西四站D口<br><strong>弥撒时间</strong>：周日6:30、8:00、10:00、18:00</p><p><a href="/beijing-travel-guide/religion/beitang.html">查看北堂详细介绍 →</a></p><h3 id="东堂-王府井天主堂" tabindex="-1">东堂（王府井天主堂） <a class="header-anchor" href="#东堂-王府井天主堂" aria-label="Permalink to &quot;东堂（王府井天主堂）&quot;">​</a></h3><p>东堂位于繁华的王府井大街，是北京最著名的天主教堂之一。教堂采用罗马式建筑风格，建于1655年。</p><p><strong>地址</strong>：东城区王府井大街74号<br><strong>交通</strong>：地铁1号线王府井站C口<br><strong>弥撒时间</strong>：周日6:30、8:00、10:00、18:00</p><p><strong>特点</strong>：</p><ul><li>位于王府井商业区，交通便利</li><li>教堂前有广场，是新人拍婚纱照的热门地点</li><li>夜景灯光很美</li></ul><h3 id="西堂-西直门天主堂" tabindex="-1">西堂（西直门天主堂） <a class="header-anchor" href="#西堂-西直门天主堂" aria-label="Permalink to &quot;西堂（西直门天主堂）&quot;">​</a></h3><p>西堂是北京四大天主教堂中规模最小的一座，采用意大利式建筑风格，建于1723年。</p><p><strong>地址</strong>：西城区西直门内大街130号<br><strong>交通</strong>：地铁2号线西直门站A口<br><strong>弥撒时间</strong>：周日6:30、8:00、10:00</p><p><strong>特点</strong>：</p><ul><li>规模较小，但历史悠久</li><li>周围是北京老城区，可体验老北京风情</li></ul><h2 id="其他著名教堂" tabindex="-1">其他著名教堂 <a class="header-anchor" href="#其他著名教堂" aria-label="Permalink to &quot;其他著名教堂&quot;">​</a></h2><h3 id="东交民巷天主堂" tabindex="-1">东交民巷天主堂 <a class="header-anchor" href="#东交民巷天主堂" aria-label="Permalink to &quot;东交民巷天主堂&quot;">​</a></h3><p>东交民巷天主堂又称圣米厄尔教堂，建于1901年，是法国传教士在东交民巷使馆区修建的。</p><p><strong>地址</strong>：东城区东交民巷甲13号<br><strong>特点</strong>：哥特式建筑，位于东交民巷使馆建筑群中</p><h3 id="西直门天主堂-西堂" tabindex="-1">西直门天主堂（西堂） <a class="header-anchor" href="#西直门天主堂-西堂" aria-label="Permalink to &quot;西直门天主堂（西堂）&quot;">​</a></h3><p>详见上文。</p><h2 id="参观须知" tabindex="-1">参观须知 <a class="header-anchor" href="#参观须知" aria-label="Permalink to &quot;参观须知&quot;">​</a></h2><h3 id="弥撒时间" tabindex="-1">弥撒时间 <a class="header-anchor" href="#弥撒时间" aria-label="Permalink to &quot;弥撒时间&quot;">​</a></h3><p>天主教堂每天都有弥撒，周日场次最多。弥撒是天主教最重要的礼仪，游客可以旁听，但不能参与领圣体。</p><h3 id="着装要求" tabindex="-1">着装要求 <a class="header-anchor" href="#着装要求" aria-label="Permalink to &quot;着装要求&quot;">​</a></h3><ul><li>避免穿短裤、背心等过于暴露的服装</li><li>女士建议穿长裙或长裤</li></ul><h3 id="行为规范" tabindex="-1">行为规范 <a class="header-anchor" href="#行为规范" aria-label="Permalink to &quot;行为规范&quot;">​</a></h3><ul><li>教堂内保持安静</li><li>弥撒期间禁止拍照</li><li>非弥撒时间拍照请勿使用闪光灯</li><li>手机调至静音</li></ul><h3 id="参观建议" tabindex="-1">参观建议 <a class="header-anchor" href="#参观建议" aria-label="Permalink to &quot;参观建议&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：周日上午弥撒后，可以参观教堂内部</li><li><strong>讲解服务</strong>：部分教堂有志愿者提供免费讲解</li><li><strong>周边游览</strong>：可结合周边景点一起游览</li></ol><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>北京的天主教堂是中西文化交流的重要见证。从利玛窦开始，西方传教士在中国传播宗教的同时，也带来了西方的科学、艺术和文化。</p><p>这些教堂的建筑风格各异，有巴洛克式、哥特式、罗马式、意大利式等，是北京建筑艺术的瑰宝。同时，它们也是研究中国近代史、中西文化交流史的重要实物资料。</p><hr><p><strong>注意</strong>：参观教堂请尊重宗教礼仪，保持安静。</p>',55)])])}const p=a(o,[["render",n]]);export{u as __pageData,p as default};
